    fn validate(&self, input: &str) -> bool;

    // Default method: validates all inputs, returns indices of failures
    fn validate_all<'a>(&self, inputs: &[&'a str]) -> Vec<&'a str> {
        inputs.iter().copied().filter(|s| !self.validate(s)).collect()
