use std::collections::HashSet;

trait IterExt: Iterator + Sized {
    fn count_unique(self) -> usize
    where
        Self::Item: Eq + std::hash::Hash,
    {
        self.collect::<HashSet<_>>().len()
    }

    fn frequencies(self) -> std::collections::HashMap<Self::Item, usize>
    where
        Self::Item: Eq + std::hash::Hash,
    {
        let mut map = std::collections::HashMap::new();
        for item in self {
            *map.entry(item).or_insert(0) += 1;
        }
        map
    }

    fn into_sorted_vec(self) -> Vec<Self::Item>
    where
        Self::Item: Ord,
    {
        let mut v: Vec<_> = self.collect();
        v.sort();
        v
    }
}

impl<I: Iterator> IterExt for I {}

fn main() {
    let v = vec![3i32, 1, 2, 2, 3, 3];
    println!("unique: {}", v.iter().copied().count_unique());
    println!("sorted: {:?}", v.iter().copied().into_sorted_vec());
    let freq = v.iter().copied().frequencies();
    println!("freq of 3: {}", freq[&3]);
}

